1	//! R1 — TERM rendering (the deep core; every other sub-target reuses this).
2	//!
3	//! Every glyph, spacing and parenthesization rule here is oracle-pinned; see
4	//! workspace/BEHAVIOR.md "Term rendering" for the probe provenance of each
5	//! case. Summary of the observed surface:
6	//!
7	//!   * sort sigils `~ $ # %` + `.idx` suffix when the index is > 0;
8	//!   * public constants `'name'`, fresh constants `~'name'`, naturals `%n`,
9	//!     DH constants `one` / `DH_neutral`;
10	//!   * application `f(a, b)` — comma attached to the preceding argument, fill
11	//!     space between arguments, wrap aligned after `(`; arity 0 renders bare;
12	//!   * tuples `<a, b, c>` — `", "` attached to each element (a wrapped line
13	//!     keeps the trailing space), right-nested pairs flattened;
14	//!   * `^` chains render flat for BOTH association orders, no parens added;
15	//!   * AC operators `*`, `⊕`, `++`, `%+` — self-parenthesized `(a*b*c)`,
16	//!     flattened across both sides, no spaces, break between elements with
17	//!     the operator attached to the preceding element;
18	//!   * `diff(l, r)` in application form.
19	
20	use crate::ast::{BinOp, SortHint, SuffixSort, Term, VarSpec};
21	use crate::doc::{
22	    beside_op, char, fcat, fsep, nest, punctuate, render_with, text, Doc,
23	};
24	
25	/// Theory-echo layout parameters (SPEC; every wrap observation in
26	/// BEHAVIOR.md reproduces at these settings).
27	pub(crate) const WIDTH: isize = 110;
28	pub(crate) const RIBBON: isize = 73;
29	
30	/// Render one term at the echo's layout parameters, starting at column 0.
31	pub fn render(t: &Term) -> String {
32	    render_with(WIDTH, RIBBON, &doc(t))
33	}
34	
35	/// The term's `Doc` (embedded by the signature/rule/formula renderers).
36	pub(crate) fn doc(t: &Term) -> Doc {
37	    match t {
38	        Term::Var(v) => text(&var_str(v)),
39	        Term::PubLit(s) => text(&format!("'{s}'")),
40	        Term::FreshLit(s) => text(&format!("~'{s}'")),
41	        Term::NatLit(s) => text(&format!("%{s}")),
42	        Term::Number(n) => text(&format!("%{n}")),
43	        Term::NumberOne => text("one"),
44	        Term::NatOne => text("%1"),
45	        Term::DhNeutral => text("DH_neutral"),
46	        Term::App(f, args) => {
47	            if args.is_empty() {
48	                text(f)
49	            } else {
50	                app_doc(f, args)
51	            }
52	        }
53	        Term::AlgApp(name, a, b) => {
54	            if name == "exp" {
55	                exp_doc(t)
56	            } else {
57	                app_doc(name, &[(**a).clone(), (**b).clone()])
58	            }
59	        }
60	        Term::Pair(elems) => pair_doc(elems),
61	        Term::Diff(l, r) => app_doc("diff", &[(**l).clone(), (**r).clone()]),
62	        Term::BinOp(BinOp::Exp, _, _) => exp_doc(t),
63	        Term::BinOp(op, _, _) => ac_doc(*op, t),
64	        // UNOBSERVABLE placeholder (BEHAVIOR.md): not oracle-pinned.
65	        Term::PatMatch(inner) => beside_op(text("="), doc(inner)),
66	    }
67	}
68	
69	/// Sigil + name + `.idx` suffix (suffix only when idx > 0). Also used for
70	/// quantifier binders, which render identically (probe:q_b1).
71	pub(crate) fn var_str(v: &VarSpec) -> String {
72	    let sigil = match v.sort {
73	        SortHint::Msg | SortHint::Untagged | SortHint::Suffix(SuffixSort::Msg) => "",
74	        SortHint::Pub | SortHint::Suffix(SuffixSort::Pub) => "$",
75	        SortHint::Fresh | SortHint::Suffix(SuffixSort::Fresh) => "~",
76	        SortHint::Node | SortHint::Suffix(SuffixSort::Node) => "#",
77	        SortHint::Nat | SortHint::Suffix(SuffixSort::Nat) => "%",
78	    };
79	    if v.idx > 0 {
80	        format!("{sigil}{}.{}", v.name, v.idx)
81	    } else {
82	        format!("{sigil}{}", v.name)
83	    }
84	}
85	
86	/// `f(a1, a2, …)`: commas attach to the preceding argument, fill space
87	/// between arguments (fsep), wrap aligns after the `(`, `)` attaches to the
88	/// last argument (probe:t_wide W2, probe:e_long).
89	fn app_doc(f: &str, args: &[Term]) -> Doc {
90	    let arg_docs = punctuate(&char(','), args.iter().map(doc).collect());
91	    beside_op(
92	        beside_op(text(&format!("{f}(")), fsep(arg_docs)),
93	        char(')'),
94	    )
95	}
96	
97	/// `<a, b, c>`: one fill whose items are `<`, each element (with attached
98	/// `", "` — a wrapped line keeps the trailing space, probe:t_wide W1,
99	/// probe:p_pw1) under `nest 1`, and `>`. The fill semantics produce every
100	/// observed wide-tuple shape (probe:p_pw1 wfa–wfd, target:mesh k2):
101	///   * fits → `<a, b>` on one line;
102	///   * elements fill-wrap at (column of `<`) + 1 (the nest 1);
103	///   * a first element whose one-liner does not fit beside `<` leaves `<`
104	///     ALONE on its line;
105	///   * `>` sits beside the last element when that element ends a fill line,
106	///     but drops to its own line at the column of `<` (no nest) when the
107	///     last element is multi-line.
108	/// A Pair in LAST position flattens into the enclosing tuple; other positions
109	/// keep their own delimiters (probe:t_pair).
110	fn pair_doc(elems: &[Term]) -> Doc {
111	    let mut flat: Vec<&Term> = Vec::new();
112	    collect_pair(elems, &mut flat);
113	    let mut items = vec![char('<')];
114	    for d in punctuate(&text(", "), flat.into_iter().map(doc).collect()) {
115	        items.push(nest(1, &d));
116	    }
117	    items.push(char('>'));
118	    fcat(items)
119	}
120	
121	fn collect_pair<'a>(elems: &'a [Term], out: &mut Vec<&'a Term>) {
122	    for (i, e) in elems.iter().enumerate() {
123	        match e {
124	            Term::Pair(inner) if i + 1 == elems.len() => collect_pair(inner, out),
125	            _ => out.push(e),
126	        }
127	    }
128	}
129	
130	/// `a^b^c`: chains flatten for BOTH association orders (probe:t_exp2), the
131	/// `^` attaches to the preceding operand, no spaces, no parens added.
132	fn exp_doc(t: &Term) -> Doc {
133	    let mut leaves: Vec<&Term> = Vec::new();
134	    collect_exp(t, &mut leaves);
135	    let docs = punctuate(&char('^'), leaves.into_iter().map(doc).collect());
136	    fcat(docs)
137	}
138	
139	fn collect_exp<'a>(t: &'a Term, out: &mut Vec<&'a Term>) {
140	    match t {
141	        Term::BinOp(BinOp::Exp, a, b) => {
142	            collect_exp(a, out);
143	            collect_exp(b, out);
144	        }
145	        Term::AlgApp(name, a, b) if name == "exp" => {
146	            collect_exp(a, out);
147	            collect_exp(b, out);
148	        }
149	        _ => out.push(t),
150	    }
151	}
152	
153	/// AC operator: `(a<op>b<op>c)` — self-parenthesized, flattened across both
154	/// sides, operator attached to the preceding element, no spaces, fcat break
155	/// between elements (probes:t_xor, t_uni, t_nat, t_mult2, t_uniwide). The
156	/// SAME single-fill construction as tuples, with `(`/`)` as fill items and
157	/// elements under `nest 1`: elements continue at (column of `(`) + 1, and
158	/// the `)` drops to its OWN line at the column of `(` when it does not fit
159	/// beside the last element (target:alethea Universal_VerProofV_v1 — the
160	/// union keeps both wide elements on one fill line and only the `)` drops;
161	/// the earlier R1 law with `)` beside-attached agreed on every R1-observed
162	/// shape but was falsified there).
163	fn ac_doc(op: BinOp, t: &Term) -> Doc {
164	    let glyph = match op {
165	        BinOp::Mult => "*",
166	        BinOp::Union => "++",
167	        BinOp::Xor => "\u{2295}",
168	        BinOp::NatPlus => "%+",
169	        BinOp::Exp => unreachable!("Exp renders via exp_doc"),
170	    };
171	    let mut leaves: Vec<&Term> = Vec::new();
172	    collect_ac(op, t, &mut leaves);
173	    let mut items = vec![char('(')];
174	    for d in punctuate(&text(glyph), leaves.into_iter().map(doc).collect()) {
175	        items.push(nest(1, &d));
176	    }
177	    items.push(char(')'));
178	    fcat(items)
179	}
180	
181	fn collect_ac<'a>(op: BinOp, t: &'a Term, out: &mut Vec<&'a Term>) {
182	    match t {
183	        Term::BinOp(o, a, b) if *o == op => {
184	            collect_ac(op, a, out);
185	            collect_ac(op, b, out);
186	        }
187	        _ => out.push(t),
188	    }
189	}
