277	pub fn pretty_closed_theory(
278	    parsed: &p::Theory,
279	    elaborated: &Theory,
280	    proved: &[ProvedLemma],
281	    wf_block: &str,
282	    build: &BuildInfo,
283	    in_file: &str,
284	    auto_sources: bool,
285	) -> String {
286	    let mut out = String::new();
287	
288	    // HS `prettyTheory` (TheoryObject.hs:741-756):
289	    //   vsep [ kwTheoryName name
290	    //        , ...configBlocks...  (filter isConfigBlock thyItems, before begin)
291	    //        , kwTheoryBegin, ... ]
292	    // ConfigBlocks: `prettyConfigBlock cb = text "configuration: " <> doubleQuotes (text cb)`
293	    // RS stores the configuration string directly in `parsed.configuration`.
294	    out.push_str("theory ");
295	    out.push_str(&elaborated.name);
296	    if let Some(cfg) = &parsed.configuration {
297	        // HS: `text "configuration: " <> doubleQuotes (text cb)`
298	        // = `configuration: "<cb>"`
299	        // Emitted via vsep (blank-line separated from theory name and begin).
300	        out.push_str("\n\nconfiguration: \"");
301	        out.push_str(cfg);
302	        out.push('"');
303	    }
304	    out.push_str("\n\nbegin\n\n");
305	
306	    // Function signature block — the `// Function signature and definition of
307	    // the equational theory E` header comment, a blank line, and the
308	    // `builtins:` / `functions:` / `equations:` declarations — all rendered by
309	    // the vendored sealed `pretty_clean` crate through the value adapter
310	    // `pretty_clean_adapt::signature_section`.  The clean renderer emits the
311	    // header itself and ends with a trailing '\n', so nothing extra is pushed
312	    // here.  See INTEGRATION_REPORT.md "pretty round-2".
313	    out.push_str(&crate::pretty_clean_adapt::signature_section(
314	        &elaborated.signature.maude_sig,
315	    ));
316	
317	    // HS `prettyTheory` (TheoryObject.hs:741-751) emits, between the
318	    // signature and the cache block, in this order:
319	    //   - `vcat $ map prettyTactic thyT` (only if non-empty tactics)
320	    //   - `heuristic: <ranking>` line (only if non-empty heuristic)
321	    //   - `ppCache` (the "looping facts with injective instances" comment).
322	    // `vsep` separates each non-empty element with a blank line.
323	    // Mirror that here.
324	    if !elaborated.tactic.is_empty() {
325	        // `vcat $ map prettyTactic thyT`: tactics joined by a single
326	        // newline (no blank line between them).
327	        let blocks: Vec<String> = elaborated.tactic.iter().map(|t| t.render()).collect();
328	        out.push('\n');
329	        out.push_str(&blocks.join("\n"));
330	        out.push('\n');
331	    }
332	    if !elaborated.heuristic.is_empty() {
333	        // HS `TheoryObject.hs:732-768, see line 749`: `text "heuristic: " <> text (prettyGoalRankings thyH)`
334	        // where `prettyGoalRankings = unwords . map prettyGoalRanking` (System.hs:707-708).
335	        // Each ranking in the Vec is a raw heuristic string; join their expansions with a
336	        // space.  (In practice there is only one `heuristic:` item per theory.)
337	        let rendered: Vec<String> = elaborated.heuristic.iter()
338	            .map(|raw| pretty_goal_rankings(raw, in_file))
339	            .collect();
340	        out.push('\n');
341	        out.push_str("heuristic: ");
342	        out.push_str(&rendered.join(" "));
343	        out.push('\n');
344	    }
345	    let inj_block = render_injective_fact_insts(elaborated);
346	    if !inj_block.is_empty() {
347	        out.push('\n');
348	        out.push_str(&inj_block);
349	        out.push('\n');
350	    }
351	
352	    // Iterate parsed.items, mapping to elaborated entities where needed.
353	    // HS preserves source order via vsep over `thyItems`.  Each item is
354	    // separated from the previous block by a blank line.
355	    //
356	    // HS-parallel: `lib/theory/src/TheoryObject.hs:732-768, see line 744,752`
357	    //   `parMap rdeepseq ppItem (theoryItems thy)` (and `OpenTheory.hs:909-949, see line 921,933`).
358	    // HS evaluates each item's `Doc` in parallel; the final `vsep`
359	    // (sequential concatenation) preserves source order.  We mirror via
360	    // rayon `par_iter().collect()` — parallel per-item render, sequential
361	    // string append.
362	    use rayon::prelude::*;
363	    // Collect macros once (mirrors HS `applyMacroInRestriction` /
364	    // `parseLemmaWithMacros`): the restriction/lemma renderers apply them to
365	    // get the expanded formula.  Computed here (not per item) so it is not
366	    // re-collected and cloned for every theory item.
367	    let macros: Vec<p::Macro> = collect_macros(parsed);
368	    // Collect predicate declarations once.  HS `expandRestriction` /
369	    // `expandLemma` (TheoryObject.hs:430-446) predicate-expand BOTH the
370	    // main and original formulas of every restriction/lemma against the
371	    // theory's predicates (which includes the builtin `Smaller`/multiset-
372	    // `(<)`), so the displayed formula is always the expanded one.  The
373	    // parse already succeeded, so every referenced predicate is defined;
374	    // using the full set for display-time expansion is safe.
375	    let predicates: Vec<p::Predicate> = collect_predicates(parsed);
376	    // Names of arity-1 NoEq function symbols.  Depends only on the
377	    // (immutable) elaborated signature, so compute it once here and thread
378	    // it through to every per-item renderer rather than recomputing (and
379	    // re-cloning the signature) for each rule/lemma/restriction/predicate.
380	    let arity1 = arity1_noeq_names(elaborated);
381	    // HS `prettyClosedTheory` (ClosedTheory.hs:382-418, see line 383) switches the WHOLE theory
382	    // to the open-as-closed renderer when `containsManualRuleVariants` holds,
383	    // which suppresses loop-breaker comments on trivial-AC-variant rules.
384	    let manual_variants = contains_manual_rule_variants(parsed, elaborated, auto_sources);
385	    // Item renderers convert formulas (`formula_to_guarded` on lemmas /
386	    // restrictions), whose term conversions read the user-fun
387	    // thread-locals — replicate the calling thread's sets onto each
388	    // render worker (a stolen thread outside any guard has EMPTY sets).
389	    let user_funs_snapshot = crate::elaborate::snapshot_user_funs();
390	    let rendered: Vec<Option<String>> = parsed.items.par_iter()
391	        .map(|item| {
392	            let _user_funs_guard =
393	                crate::elaborate::set_user_funs_from_collected(&user_funs_snapshot);
394	            render_parsed_item(item, &macros, &predicates, elaborated, proved, in_file, &arity1, manual_variants, auto_sources)
395	        })
396	        .collect();
397	    for b in rendered.into_iter().flatten() {
398	        out.push('\n');
399	        out.push_str(&b);
400	        out.push('\n');
401	    }
402	
403	    // Wellformedness block (already preformatted: either the "all
404	    // successful" line or the WARNING /* ... */ block).
405	    out.push('\n');
406	    out.push_str(wf_block);
407	    out.push('\n');
408	
409	    // Generated-from block.
410	    out.push('\n');
411	    out.push_str(&render_generated_from(build));
412	    out.push('\n');
413	
414	    // end
415	    out.push_str("\nend\n");
416	
417	    out
418	}
