523	/// Render HS `ppInjectiveFactInsts` (ClosedTheory.hs:413-418):
524	///
525	/// ```text
526	/// /*
527	/// looping facts with injective instances:
528	///   T1/n1, T2/n2, ...
529	/// */
530	/// ```
531	///
532	/// HS:
533	/// ```haskell
534	/// multiComment $ sep
535	///   [ text "looping facts with injective instances:"
536	///   , nest 2 $ fsepList (text . showFactTagArity) (map fst tags) ]
537	/// ```
538	/// where `multiComment d = comment $ fsep [text "/*", d, text "*/"]`
539	/// (Pretty.hs:102-103) and `fsepList pp = fsep . punctuate comma . map pp`
540	/// (Pretty.hs:88-89).
541	///
542	/// Emits the empty string when no fact tags are injective.  Computes
543	/// the set on demand from the elaborated rules + reducible function
544	/// symbols — same call site as `ProofContext::new`
545	/// (`constraint/solver/context.rs:493-495`).
546	fn render_injective_fact_insts(elab: &Theory) -> String {
547	    use crate::pretty_hpj::{self as hpj, Doc, punctuate};
548	    use crate::fact::{FactTag, Multiplicity};
549	    let proto_rules: Vec<&crate::rule::ProtoRuleE> = elab.rules()
550	        .map(|r| &r.rule)
551	        .collect();
552	    let mut tags = crate::tools::injective_fact_instances::simple_injective_fact_instances(
553	        &proto_rules,
554	        &elab.signature.maude_sig.reducible_fun_syms_fast,
555	    );
556	    // HS `closeRuleCache` (Rule.hs:147-150): union the FORCED injective facts
557	    // (`setforcedInjectiveFacts {L_PureState, L_CellLocked}`, Sapic.hs:84) when
558	    // the state-channel optimisation is on.
559	    if elab.options.state_channel_opt {
560	        tags = crate::tools::injective_fact_instances::union_forced_injective_fact_instances(
561	            tags,
562	            &crate::tools::injective_fact_instances::pure_state_forced_fact_tags(),
563	        );
564	    }
565	    if tags.is_empty() { return String::new(); }
566	    // HS `showFactTagArity` (Fact.hs:521-525, see line 526): persistent `!`-prefix + name
567	    // + `/` + arity.
568	    let label = |tag: &FactTag| -> String {
569	        let prefix = match tag {
570	            FactTag::Proto(Multiplicity::Persistent, _, _) => "!",
571	            _ => "",
572	        };
573	        format!("{}{}/{}",
574	            prefix,
575	            crate::fact::fact_tag_name(tag),
576	            crate::fact::fact_tag_arity(tag))
577	    };
578	    let tag_docs: Vec<Doc> = tags.iter().map(|(t, _)| Doc::text(label(t))).collect();
579	    // fsepList (text . showFactTagArity) (map fst tags)
580	    let list_doc = hpj::fsep(punctuate(Doc::text(","), tag_docs));
581	    // sep [text "looping facts...", nest 2 list_doc]
582	    let inner = hpj::sep(vec![
583	        Doc::text("looping facts with injective instances:"),
584	        list_doc.nest(2),
585	    ]);
586	    // multiComment inner = comment $ fsep [text "/*", inner, text "*/"]
587	    let doc = hpj::fsep(vec![Doc::text("/*"), inner, Doc::text("*/")]);
588	    doc.render()
589	}
