595	fn render_signature(sig: &tamarin_term::maude_sig::MaudeSig) -> String {
596	    let mut out = String::new();
597	
598	    // builtins: ...  (only if any enabled)
599	    let mut builtins: Vec<&str> = Vec::new();
600	    if sig.enable_dh { builtins.push("diffie-hellman"); }
601	    if sig.enable_bp { builtins.push("bilinear-pairing"); }
602	    if sig.enable_mset { builtins.push("multiset"); }
603	    if sig.enable_nat { builtins.push("natural-numbers"); }
604	    if sig.enable_xor { builtins.push("xor"); }
605	    if !builtins.is_empty() {
606	        // HS renders builtins via the same `ppNonEmptyList'` as functions:
607	        // `(keyword_ "builtins:" <->) . fsep . punctuate comma`
608	        // (Term/Maude/Signature.hs:220-247,229-231) — so the list wraps through
609	        // the HughesPJ engine, not a flat join.
610	        out.push_str(&wrap_with_lead("builtins:", &builtins));
611	        out.push('\n');
612	    }
613	
614	    // functions: ...
615	    let funs = render_fun_syms(sig);
616	    if !funs.is_empty() {
617	        out.push_str(&wrap_with_lead("functions:", &funs));
618	        out.push('\n');
619	    }
620	
621	    // equations: ...
622	    let eqs = render_equations(sig);
623	    if !eqs.is_empty() {
624	        let key = if sig.eq_convergent { "equations [convergent]:" } else { "equations:" };
625	        // HS uses `sep [hdr, nest 2 (punctuate comma ds)]` for the
626	        // equations list — yields `hdr\n    eq1,\n    eq2,...` when
627	        // multiple equations.
628	        out.push_str(&sep_block_with_lead(key, &eqs));
629	        out.push('\n');
630	    }
631	
632	    out
633	}
