635	/// Render the function symbol list, sorted alphabetically by name (HS
636	/// uses `S.toList` over a Set ordered by the same key).
637	fn render_fun_syms(sig: &tamarin_term::maude_sig::MaudeSig) -> Vec<String> {
638	    use tamarin_term::function_symbols::{Constructability, Privacy};
639	    let mut items: Vec<(String, String)> = sig.st_fun_syms.iter().map(|sym| {
640	        let name = String::from_utf8_lossy(sym.name).to_string();
641	        let arity = sym.arity;
642	        let attr = match (sym.privacy, sym.constructability) {
643	            (Privacy::Public, Constructability::Constructor) => "",
644	            (Privacy::Public, Constructability::Destructor) => "[destructor]",
645	            (Privacy::Private, Constructability::Constructor) => "[private,constructor]",
646	            (Privacy::Private, Constructability::Destructor) => "[private,destructor]",
647	        };
648	        let rendered = format!("{}/{}{}", name, arity, attr);
649	        (name, rendered)
650	    }).collect();
651	    items.sort_by(|a, b| a.0.cmp(&b.0));
652	    items.into_iter().map(|(_, s)| s).collect()
653	}
