655	/// Render the equation list.  Each `CtxtStRule` has an LHS term and an
656	/// RHS term (after reading positions/term out of `StRhs`).  HS renders
657	/// `prettyCtxtStRule $ S.toList (stRules sig)` (Term/Maude/Signature.hs:220-247, see line 226),
658	/// i.e. equations in `S.toList` order.  `CtxtStRule` derives structural `Ord`,
659	/// so we emit them in the `st_rules` `BTreeSet` iteration order, which mirrors
660	/// HS's `S.toList` exactly.  We must NOT re-sort by the rendered pretty-string,
661	/// since that diverges from the structural (term-tree) order (e.g. AC products
662	/// pretty-print with a leading `(`, `exp` as infix `a^b`).
663	///
664	/// Each side is returned as a HughesPJ `Doc` (not a flat string) so that wide
665	/// function applications wrap at the ribbon width exactly as HS
666	/// `prettyCtxtStRule`/`prettyLNTerm` (SubtermRule.hs:122-123, Term.hs:295-296)
667	/// — the `ppFun f ts = text (f++"(") <> fsep (punctuate comma …) <> ")"` `fsep`
668	/// breaks at argument boundaries when the term overruns.  We reach the Doc path
669	/// by converting the `LNTerm` to a parser-AST `p::Term` (`lnterm_to_parser`,
670	/// the same conversion already used elsewhere) and rendering it through
671	/// `pf::term_doc` (= HS `prettyTerm`).
672	fn render_equations(sig: &tamarin_term::maude_sig::MaudeSig) -> Vec<(crate::pretty_hpj::Doc, crate::pretty_hpj::Doc)> {
673	    let mut items = Vec::new();
674	    for r in &sig.st_rules {
675	        let lhs = pf::term_doc(&lnterm_to_parser(&r.lhs));
676	        let rhs = pf::term_doc(&lnterm_to_parser(&r.rhs.term));
677	        items.push((lhs, rhs));
678	    }
679	    items
680	}
