1178	/// HS `prettyMacros` / `prettyMacro` (TheoryObject.hs:819-840).
1179	///
1180	/// HS: `prettyMacros m = keyword_ "macros:" $$ nest 4 (vcat [macros...])`
1181	/// HS: `prettyMacro (op, args, out) =
1182	///       vcat [ppNonEmptyList (\ds -> sep (map (nest 4) ds)) text [op++"("]
1183	///             <-> prettyVarList args <-> text ") = " <-> prettyTerm show out]`
1184	///
1185	/// `ppNonEmptyList hdr pp [x] = hdr [pp x] = sep [nest 4 (text x)]`
1186	/// = `nest 4 (text (name++"("))`.
1187	///
1188	/// With `keyword_ "macros:" $$ nest 4 (nest 4 "name(" <+> args <+> ") = " <+> body)`:
1189	/// the double-nest (8 total) combined with `keyword_`'s 7-char width makes
1190	/// `nil_above_nest` inline the content (k = -7+8 = 1 > 0), putting everything
1191	/// on ONE line: `macros: name( args ) =  body`.
1192	///
1193	/// For multiple macros, each is nested 4 levels inside the outer `nest 4`,
1194	/// giving 8-space indent on subsequent lines.
1195	fn render_parsed_macros(macros: &[p::Macro]) -> String {
1196	    use crate::pretty_hpj::{self as hpj, Doc};
1197	
1198	    let last_idx = macros.len() - 1;
1199	    let macro_docs: Vec<Doc> = macros.iter().enumerate().map(|(i, m)| {
1200	        // HS: `ppNonEmptyList (\ds -> sep (map (nest 4) ds)) text [op++"("]`
1201	        // = `sep [nest 4 (text (op ++ "("))]` = `nest 4 (text (op ++ "("))`.
1202	        let name_open = Doc::text(format!("{}(", m.name)).nest(4);
1203	        // HS: `prettyVarList args = fsep . punctuate comma . map prettyLVar`
1204	        // For macro args (bare LVar names, sort-prefix from hint):
1205	        let args_parts: Vec<String> = m.args.iter().map(|v| {
1206	            let mut s = pf::sort_prefix_from_hint(v.sort).to_string();
1207	            s.push_str(&v.name);
1208	            if v.idx > 0 { s.push('.'); s.push_str(&v.idx.to_string()); }
1209	            s
1210	        }).collect();
1211	        let args_str = args_parts.join(", ");
1212	        // HS: `prettyTerm (text . show) body`
1213	        let body_str = pf::pretty_term(&m.body);
1214	        // Build: `nest 4 "name(" <+> args <+> ") = " <+> body`
1215	        // HS <-> = HughesPJ <+> (beside with space = beside_sp).
1216	        let mut doc = name_open;
1217	        if !m.args.is_empty() {
1218	            doc = doc.beside_sp(Doc::text(args_str));
1219	        }
1220	        doc = doc.beside_sp(Doc::text(") = "));
1221	        doc = doc.beside_sp(Doc::text(body_str));
1222	        // HS: last macro has no trailing comma
1223	        if i < last_idx {
1224	            doc.beside(Doc::text(","))
1225	        } else {
1226	            doc
1227	        }
1228	    }).collect();
1229	
1230	    // HS: `keyword_ "macros:" $$ nest 4 (vcat macro_docs)`
1231	    let body = hpj::vcat(macro_docs).nest(4);
1232	    let header = Doc::text("macros:");
1233	    header.above(body).render()
1234	}
