1250	/// Render a rule's attribute block `[...]`, mirroring HS `prettyRuleAttributes`
1251	/// / `prettyRuleAttribute` (Model/Rule.hs:1191-1205).  HS emits a FIXED-order
1252	/// `catMaybes [color, process, no_derivcheck, issapicrule, role]` joined by
1253	/// `fsep . punctuate comma` (", "), wrapped in `[`..`]`; empty → nothing.
1254	/// External (`x-…`) attributes are NOT in HS's list, so they are dropped.
1255	/// Build HS `prettyRuleAttribute`'s ordered part list (Model/Rule.hs:1192-1198).
1256	///
1257	/// HS stores the parsed attribute LIST folded into a `RuleAttributes` STRUCT via
1258	/// its `Semigroup` (Model/Rule.hs:370-385): for the `Maybe`-typed fields
1259	/// (`ruleColor`, `role`) `preferRight a b = if isJust b then b else a` ⇒ the
1260	/// LAST occurrence wins.  RS therefore takes the LAST match, not the first
1261	/// (`rev().find_map(..)`).  `no_derivcheck`/`issapicrule` are booleans combined
1262	/// with `||`, so order-independent (`.any(..)`).
1263	///
1264	/// Render order is the `catMaybes [color, process, no_derivcheck, issapicrule,
1265	/// role]` of `prettyRuleAttribute`.  HS's attribute parser `parseAndIgnore`s
1266	/// `process=` (Parser/Rule.hs:68-93, see line 72), so a user-written `process=` never sets
1267	/// `ruleProcess` and is never rendered; RS mirrors this by discarding `process=`
1268	/// at parse time (no `RuleAttr::Process` variant exists).  `process=` is only
1269	/// emitted by HS for SAPIC-translation-generated rules (via `ruleProcess`),
1270	/// which RS does not yet translate, so there is nothing to render here.
1271	fn rule_attribute_parts(attrs: &[p::RuleAttr]) -> Vec<String> {
1272	    let mut parts: Vec<String> = Vec::new();
1273	    // color= : HS `text "color=" <> text (rgbToHex c)`; `rgbToHex` is
1274	    // `'#':` + lowercase 2-digit-per-channel hex (Data/Color.hs:140-147, see line 141).
1275	    if let Some(hex) = attrs.iter().rev().find_map(|a| match a {
1276	        p::RuleAttr::Color(c) => Some(c), _ => None }) {
1277	        parts.push(format!("color=#{}", hex.trim_start_matches('#').to_lowercase()));
1278	    }
1279	    // process= : HS `ppProcess p = text "process=" <> "\"" ++ topLevel ++ "\""`
1280	    // (Model/Rule.hs:1201-1215, see line 1210).  Rendered between color= and no_derivcheck.  Only
1281	    // SAPIC-translation-generated rules carry it (the parser ignores a
1282	    // user-written `process=`); the LAST occurrence wins (Maybe field).
1283	    if let Some(s) = attrs.iter().rev().find_map(|a| match a {
1284	        p::RuleAttr::Process(s) => Some(s), _ => None }) {
1285	        parts.push(format!("process=\"{}\"", s));
1286	    }
1287	    if attrs.iter().any(|a| matches!(a, p::RuleAttr::NoDerivCheck)) {
1288	        parts.push("no_derivcheck".to_string());
1289	    }
1290	    if attrs.iter().any(|a| matches!(a, p::RuleAttr::IsSapicRule)) {
1291	        parts.push("issapicrule".to_string());
1292	    }
1293	    if let Some(r) = attrs.iter().rev().find_map(|a| match a {
1294	        p::RuleAttr::Role(r) => Some(r), _ => None }) {
1295	        parts.push(format!("role='{}'", r));
1296	    }
1297	    parts
1298	}
