1824	pub(crate) fn lnterm_to_parser(t: &tamarin_term::lterm::LNTerm) -> p::Term {
1825	    use tamarin_term::function_symbols::{AcSym, FunSym};
1826	    use tamarin_term::term::Term;
1827	    use tamarin_term::vterm::Lit;
1828	    use tamarin_term::lterm::LSort;
1829	    match t {
1830	        Term::Lit(Lit::Var(v)) => {
1831	            let sort = match v.sort {
1832	                LSort::Pub => p::SortHint::Pub,
1833	                LSort::Fresh => p::SortHint::Fresh,
1834	                LSort::Node => p::SortHint::Node,
1835	                LSort::Nat => p::SortHint::Nat,
1836	                LSort::Msg => p::SortHint::Msg,
1837	            };
1838	            p::Term::Var(p::VarSpec {
1839	                name: v.name.to_string(),
1840	                idx: v.idx,
1841	                sort,
1842	                typ: None,
1843	            })
1844	        }
1845	        Term::Lit(Lit::Con(n)) => {
1846	            use tamarin_term::lterm::NameTag;
1847	            match n.tag {
1848	                NameTag::Pub => p::Term::PubLit(n.id.0.to_string()),
1849	                NameTag::Fresh => p::Term::FreshLit(n.id.0.to_string()),
1850	                NameTag::Nat => p::Term::NatLit(n.id.0.to_string()),
1851	                NameTag::Node => p::Term::PubLit(n.id.0.to_string()),
1852	            }
1853	        }
1854	        Term::App(FunSym::NoEq(sym), args) => {
1855	            let name = String::from_utf8_lossy(sym.name).to_string();
1856	            // `exp` is the DH exponentiation infix operator — HS
1857	            // `prettyTerm` (Term/Term.hs:272-300, see line 274) renders `exp(a, b)` as `a^b`.
1858	            // Surface as `p::Term::BinOp(Exp, ..)` so `pp_term`'s special
1859	            // case applies.
1860	            if name == "exp" && args.len() == 2 {
1861	                return p::Term::BinOp(
1862	                    p::BinOp::Exp,
1863	                    Box::new(lnterm_to_parser(&args[0])),
1864	                    Box::new(lnterm_to_parser(&args[1])),
1865	                );
1866	            }
1867	            // `pair` chains flatten to n-ary tuple (HS `prettyTerm` at
1868	            // Term/Term.hs:272-300, see line 277,292-293: `split` walks the right child
1869	            // while it is itself a pair).
1870	            if name == "pair" && args.len() == 2 {
1871	                let mut items: Vec<p::Term> = Vec::new();
1872	                items.push(lnterm_to_parser(&args[0]));
1873	                let mut tail = &args[1];
1874	                loop {
1875	                    match tail {
1876	                        Term::App(FunSym::NoEq(s2), a2)
1877	                            if a2.len() == 2 && String::from_utf8_lossy(s2.name) == "pair" =>
1878	                        {
1879	                            items.push(lnterm_to_parser(&a2[0]));
1880	                            tail = &a2[1];
1881	                        }
1882	                        _ => {
1883	                            items.push(lnterm_to_parser(tail));
1884	                            break;
1885	                        }
1886	                    }
1887	                }
1888	                return p::Term::Pair(items);
1889	            }
1890	            p::Term::App(name, args.iter().map(lnterm_to_parser).collect())
1891	        }
1892	        Term::App(FunSym::C(_), args) => {
1893	            p::Term::App("em".to_string(), args.iter().map(lnterm_to_parser).collect())
1894	        }
1895	        Term::App(FunSym::Ac(ac), args) => {
1896	            // Render AC as left-assoc binops to preserve display.
1897	            let op = match ac {
1898	                AcSym::Mult => p::BinOp::Mult,
1899	                AcSym::Union => p::BinOp::Union,
1900	                AcSym::NatPlus => p::BinOp::NatPlus,
1901	                AcSym::Xor => p::BinOp::Xor,
1902	            };
1903	            let mut it = args.iter();
1904	            let first = lnterm_to_parser(it.next().expect("AC needs at least one arg"));
1905	            it.fold(first, |acc, next| {
1906	                p::Term::BinOp(op, Box::new(acc), Box::new(lnterm_to_parser(next)))
1907	            })
1908	        }
1909	        Term::App(FunSym::List, args) => {
1910	            p::Term::App("LIST".to_string(), args.iter().map(lnterm_to_parser).collect())
1911	        }
1912	    }
1913	}
