// ── facts / rules: parser AST -> clean AST (1:1 structural value translation) ─

/// Structural conversion of a parser-AST fact into the clean-AST fact. The
/// term/annotation transforms (arity-1 fold, AC canonicalisation, macro
/// expansion) are performed PORTED-side before this call; here we only re-shape
/// the value.
pub fn fact(f: &p::Fact) -> c::Fact {
    c::Fact {
        persistent: f.persistent,
        name: f.name.clone(),
        args: f.args.iter().map(term).collect(),
        annotations: f.annotations.iter().map(fact_annotation).collect(),
    }
}

fn fact_annotation(a: &p::FactAnnotation) -> c::FactAnnotation {
    match a {
        p::FactAnnotation::SolveFirst => c::FactAnnotation::SolveFirst,
        p::FactAnnotation::SolveLast => c::FactAnnotation::SolveLast,
        p::FactAnnotation::NoSources => c::FactAnnotation::NoSources,
    }
}

/// Structural conversion of one rule attribute. The `color` value is
/// `#`-stripped and lowercased here (the closed-theory representation the
/// ported `rgbToHex` produces), a value normalisation only — the clean crate
/// re-attaches the `#` and renders the canonical attribute order/selection.
fn rule_attr(a: &p::RuleAttr) -> c::RuleAttr {
    match a {
        p::RuleAttr::Color(hex) => {
            c::RuleAttr::Color(hex.trim_start_matches('#').to_lowercase())
        }
        p::RuleAttr::NoDerivCheck => c::RuleAttr::NoDerivCheck,
        p::RuleAttr::Role(r) => c::RuleAttr::Role(r.clone()),
        p::RuleAttr::IsSapicRule => c::RuleAttr::IsSapicRule,
        p::RuleAttr::Process(s) => c::RuleAttr::Process(s.clone()),
        p::RuleAttr::External(k, v) => c::RuleAttr::External(k.clone(), v.clone()),
    }
}

fn clean_rule(
    name: &str,
    modulo: Option<&str>,
    attrs: &[p::RuleAttr],
    prems: &[p::Fact],
    acts: &[p::Fact],
    concs: &[p::Fact],
    loop_breakers: &[usize],
) -> c::Rule {
    c::Rule {
        name: name.to_string(),
        modulo: modulo.map(str::to_string),
        attributes: attrs.iter().map(rule_attr).collect(),
        premises: prems.iter().map(fact).collect(),
        actions: acts.iter().map(fact).collect(),
        conclusions: concs.iter().map(fact).collect(),
        loop_breakers: loop_breakers.to_vec(),
    }
}

/// Pre-computed AC-variant inputs (all parser values; every transform stays
/// ported). The clean crate consumes these to render the `variants (modulo
/// AC)` comment.
pub struct AcVariantsInput<'a> {
    pub ac_attrs: &'a [p::RuleAttr],
    pub ac_prems: &'a [p::Fact],
    pub ac_acts: &'a [p::Fact],
    pub ac_concs: &'a [p::Fact],
    pub ac_loop_breakers: &'a [usize],
    /// Numbered substitution groups, each a `(domain-var, range-term)` list;
    /// empty (the outer Vec) means no `variants (modulo AC)` sub-block.
    pub substitutions: Vec<Vec<(p::Term, p::Term)>>,
}

/// One whole rule block, rendered by the clean crate. `name`/`e_*` describe the
/// modulo-E rule (facts already fully transformed ported-side);
/// `outer_loop_breakers` is the (already gated) outer loop-breaker index list;
/// `variants` is `None` for the trivial-AC-variant one-liner, else the
/// pre-computed AC-variant comment inputs. Drop-in for the ported `render_rule`
/// theory-body call.
pub fn rule_section(
    name: &str,
    attrs: &[p::RuleAttr],
    e_prems: &[p::Fact],
    e_acts: &[p::Fact],
    e_concs: &[p::Fact],
    outer_loop_breakers: &[usize],
    variants: Option<AcVariantsInput>,
) -> String {
    let e_rule = clean_rule(
        name, Some("E"), attrs, e_prems, e_acts, e_concs, outer_loop_breakers,
    );
    let ac = variants.map(|v| c::AcVariants {
        ac_rule: clean_rule(
            name, Some("AC"), v.ac_attrs, v.ac_prems, v.ac_acts, v.ac_concs,
            v.ac_loop_breakers,
        ),
        substitutions: v
            .substitutions
            .iter()
            .map(|group| group.iter().map(|(l, r)| (term(l), term(r))).collect())
            .collect(),
    });
    crate::pretty_clean::render_rule(&e_rule, ac.as_ref())
}

