                .iter().map(canonicalize_ac_in_pfact).collect();
            let ac_loop_breakers: Vec<usize> =
                r.loop_breakers.iter().map(|b| b.0).collect();
            // HS `ppVariants (Disj [subst]) | subst == emptySubstVFresh =
            // emptyDoc` (Rule.hs:1289): only emit the numbered substitution
            // sub-block when there is a residual disjunction beyond identity.
            let has_residual_variants =
                r.variant_substs.iter().any(|sub| !sub.is_empty());
            let substitutions: Vec<Vec<(p::Term, p::Term)>> = if has_residual_variants {
                r.variant_substs.iter().map(|subst| {
                    subst.to_list().iter().map(|(v, t)| {
                        (lvar_to_parser_term(v), lnterm_to_parser(t))
                    }).collect()
                }).collect()
            } else {
                Vec::new()
            };
            (ac_prems, ac_acts, ac_concs, ac_loop_breakers, substitutions)
        })
    };
    let variants_input = variants.as_ref().map(
        |(ac_prems, ac_acts, ac_concs, ac_loop_breakers, substitutions)| {
            crate::pretty_clean_adapt::AcVariantsInput {
                ac_attrs: &parsed_rule.attributes,
                ac_prems,
                ac_acts,
                ac_concs,
                ac_loop_breakers,
                substitutions: substitutions.clone(),
            }
        },
    );

    crate::pretty_clean_adapt::rule_section(
        name,
        &parsed_rule.attributes,
        &e_prems,
        &e_acts,
        &e_concs,
        &outer_loop_breakers,
        variants_input,
    )
}

/// Convert an `LVar` (a variant substitution's domain variable) into a
/// parser-AST `Var` term, mirroring [`lnterm_to_parser`]'s `Lit::Var` branch so
/// the clean renderer prints it via the same sort-sigil rule as the range term.
fn lvar_to_parser_term(v: &tamarin_term::lterm::LVar) -> p::Term {
    use tamarin_term::lterm::LSort;
    let sort = match v.sort {
        LSort::Pub => p::SortHint::Pub,
        LSort::Fresh => p::SortHint::Fresh,
        LSort::Node => p::SortHint::Node,
        LSort::Nat => p::SortHint::Nat,
        LSort::Msg => p::SortHint::Msg,
    };
    p::Term::Var(p::VarSpec { name: v.name.to_string(), idx: v.idx, sort, typ: None })
}

