732	/// (one keyword per node), so we greedily collect the var-specs of all
733	/// directly-nested same-kind nodes and return the innermost body.
734	fn open_formula_prefix<'a>(
735	    is_forall: bool,
736	    vs: &'a [p::VarSpec],
737	    body: &'a p::Formula,
738	) -> (Vec<&'a p::VarSpec>, &'a p::Formula) {
739	    let mut collected: Vec<&p::VarSpec> = vs.iter().collect();
740	    let mut cur = body;
741	    loop {
742	        match cur {
743	            p::Formula::Forall(vs2, body2) if is_forall => {
744	                collected.extend(vs2.iter());
745	                cur = body2.as_ref();
746	            }
747	            p::Formula::Exists(vs2, body2) if !is_forall => {
748	                collected.extend(vs2.iter());
749	                cur = body2.as_ref();
