// =============================================================================
// Sort/name resolution pre-pass (feeds the sort-literal clean renderer)
// =============================================================================
//
// The ported string/Doc printers resolve each variable's sort inline: a
// timepoint position forces `Node`, an `Untagged` message ref unifies onto its
// binder's sort, and each quantifier binder gets a `Precise`-allocated display
// name (with a `.<idx>` suffix under shadowing).  A sort-LITERAL renderer (the
// clean pretty-printer) has no scope, so it needs a formula whose VarSpec sorts
// and names are ALREADY resolved.  `resolve_formula_sorts` produces exactly
// that, reusing the SAME scope machinery (`open_formula_prefix`,
// `allocate_formula_binders_refs`, `resolved_sort_pos`, `lookup_display`,
// `PreciseFreshState`) as the ported printers, and collapsing consecutive
// same-kind quantifiers (HS `openFormulaPrefix`) so a multi-keyword binder
// block becomes one node.  It emits NO layout — purely sort/name resolution.

/// Resolve every variable's sort + display name in `f` and collapse
/// consecutive same-kind quantifiers, so the result renders byte-identically
/// through a sort-literal formula renderer.
pub(crate) fn resolve_formula_sorts(f: &p::Formula) -> p::Formula {
    let mut state = avoid_precise_formula(f);
    resolve_formula(f, &[], &mut state)
}

fn resolve_formula(f: &p::Formula, scope: &[Bind], state: &mut PreciseFreshState) -> p::Formula {
    use p::Formula::*;
    match f {
        True => True,
        False => False,
        Atom(a) => Atom(resolve_atom(a, scope)),
        Not(g) => Not(Box::new(resolve_formula(g, scope, state))),
        And(l, r) => And(
            Box::new(resolve_formula(l, scope, state)),
            Box::new(resolve_formula(r, scope, state)),
        ),
        Or(l, r) => Or(
            Box::new(resolve_formula(l, scope, state)),
            Box::new(resolve_formula(r, scope, state)),
        ),
        Implies(l, r) => Implies(
            Box::new(resolve_formula(l, scope, state)),
            Box::new(resolve_formula(r, scope, state)),
        ),
        Iff(l, r) => Iff(
            Box::new(resolve_formula(l, scope, state)),
            Box::new(resolve_formula(r, scope, state)),
        ),
        Forall(vs, body) => resolve_qua(true, vs, body, scope, state),
        Exists(vs, body) => resolve_qua(false, vs, body, scope, state),
    }
}

/// Mirror of [`pp_qua`]: collapse consecutive same-kind quantifiers, allocate
/// binder display names, resolve the body under the extended scope — producing
/// a single quantifier node with resolved binder VarSpecs.
fn resolve_qua(
    is_forall: bool,
    vs: &[p::VarSpec],
    body: &p::Formula,
    scope: &[Bind],
    state: &mut PreciseFreshState,
) -> p::Formula {
    state.scope_freshness(|state| {
        let (all_vs, inner_body) = open_formula_prefix(is_forall, vs, body);
        let new_scope = allocate_formula_binders_refs(&all_vs, scope, state);
        // Binder VarSpecs from the newly-added scope entries: the display name
        // (which may already carry `.idx`) becomes the VarSpec name at idx 0,
        // with the binder's source sort — matching `pp_qua`'s
        // `sortPrefix(b.1) ++ b.2`.
        let binders: Vec<p::VarSpec> = new_scope[scope.len()..]
            .iter()
            .map(|b| p::VarSpec { name: b.2.clone(), idx: 0, sort: b.1, typ: None })
            .collect();
        let resolved_body = resolve_formula(inner_body, &new_scope, state);
        if is_forall {
            p::Formula::Forall(binders, Box::new(resolved_body))
        } else {
            p::Formula::Exists(binders, Box::new(resolved_body))
        }
    })
}

fn resolve_atom(a: &p::Atom, scope: &[Bind]) -> p::Atom {
    use p::Atom::*;
    match a {
        Eq(l, r) => Eq(resolve_term(l, scope, false), resolve_term(r, scope, false)),
        // `<` / `last` timepoints are temporal (HS `pp_temporal_term`).
        Less(l, r) => Less(resolve_term(l, scope, true), resolve_term(r, scope, true)),
        LessMset(l, r) => {
            LessMset(resolve_term(l, scope, false), resolve_term(r, scope, false))
        }
        Subterm(l, r) => {
            Subterm(resolve_term(l, scope, false), resolve_term(r, scope, false))
        }
        Action(fa, t) => Action(resolve_fact(fa, scope), resolve_term(t, scope, true)),
        Last(t) => Last(resolve_term(t, scope, true)),
        Pred(fa) => Pred(resolve_fact(fa, scope)),
    }
}

fn resolve_fact(fa: &p::Fact, scope: &[Bind]) -> p::Fact {
    p::Fact {
        persistent: fa.persistent,
        name: fa.name.clone(),
        args: fa.args.iter().map(|t| resolve_term(t, scope, false)).collect(),
        annotations: fa.annotations.clone(),
    }
}

/// Resolve the variables inside a term. `temporal` applies ONLY to a top-level
/// `Var` (HS `pp_temporal_term`): a non-var temporal position falls through to
/// ordinary message-term resolution.
fn resolve_term(t: &p::Term, scope: &[Bind], temporal: bool) -> p::Term {
    use p::Term::*;
    match t {
        Var(v) => Var(resolve_var(v, scope, temporal)),
        App(n, args) => App(
            n.clone(),
            args.iter().map(|a| resolve_term(a, scope, false)).collect(),
        ),
        AlgApp(n, l, r) => AlgApp(
            n.clone(),
            Box::new(resolve_term(l, scope, false)),
            Box::new(resolve_term(r, scope, false)),
        ),
        Pair(items) => {
            Pair(items.iter().map(|a| resolve_term(a, scope, false)).collect())
        }
        Diff(l, r) => Diff(
            Box::new(resolve_term(l, scope, false)),
            Box::new(resolve_term(r, scope, false)),
        ),
        BinOp(op, l, r) => BinOp(
            *op,
            Box::new(resolve_term(l, scope, false)),
            Box::new(resolve_term(r, scope, false)),
        ),
        PatMatch(inner) => PatMatch(Box::new(resolve_term(inner, scope, false))),
        PubLit(_) | FreshLit(_) | NatLit(_) | Number(_) | NumberOne | NatOne
        | DhNeutral => t.clone(),
    }
}

/// Resolve one variable occurrence to its rendered sort + display name,
/// mirroring [`pp_var_scoped_pos`] but emitting a VarSpec instead of text: a
/// bound occurrence takes the binder's sort and display name (encoded as the
/// name at idx 0); a free occurrence keeps its source name/idx with the
/// position-resolved sort.
fn resolve_var(v: &p::VarSpec, scope: &[Bind], temporal: bool) -> p::VarSpec {
    let sort = resolved_sort_pos(v, scope, temporal);
    if let Some((bsort, display)) = lookup_display(&v.name, v.idx, sort, scope) {
        p::VarSpec { name: display, idx: 0, sort: bsort, typ: v.typ.clone() }
    } else {
        p::VarSpec { name: v.name.clone(), idx: v.idx, sort, typ: v.typ.clone() }
    }
}

