fn render_parsed_lemma(lem: &p::Lemma, macros: &[p::Macro], predicates: &[p::Predicate], proved: &[ProvedLemma], in_file: &str, _elab: &Theory, arity1: &std::collections::HashSet<String>) -> String {
    // Whole lemma block routed through the vendored clean crate: it renders the
    // header (`lemma name [attrs]:`), the `all-traces|exists-trace "formula"`
    // statement (via the clean formula renderer), the guarded-formula comment
    // FRAME, and the proof tail.  Every solver/closure-entangled input stays
    // ported and is fed in as values: the fully-transformed statement formula,
    // the oracle-expanded heuristic values, the guarded-formula comment TEXT
    // (from the ported guarded transform), and the proof body.

    // Statement formula: HS does NOT macro-expand the lemma statement (only the
    // guarded block), so this is the macro-FORM formula — predicate-expanded,
    // arity-1 folded (HS `naryOpApp` k==1), AC-canonicalised (HS `fAppAC`), then
    // sort/name-resolved for the sort-literal clean renderer.
    let expanded_formula = expand_predicates_for_display(&lem.formula, predicates);
    let folded_formula = crate::elaborate::rewrite_arity1_formula(&expanded_formula, arity1);
    let canon_formula = crate::elaborate::canonicalize_ac_in_formula(&folded_formula);
    let stmt_formula = pf::resolve_formula_sorts(&canon_formula);

    // Lemma attributes with the `heuristic=` value ALREADY oracle-expanded
    // (HS `prettyGoalRankings`, file-dependent) — the clean crate renders the
    // value verbatim, so the expansion stays ported here.  Attributes the clean
    // crate does not model (none occur in the corpus echo) are dropped by the
    // adapter.
    let attrs: Vec<p::LemmaAttr> = lem.attributes.iter().map(|a| match a {
        p::LemmaAttr::Heuristic(raw) => {
            p::LemmaAttr::Heuristic(pretty_goal_rankings(raw, in_file))
        }
        other => other.clone(),
    }).collect();

    // Guarded-formula comment body — opaque input from the ported guarded
    // transform (the negation for all-traces, `pretty_guarded_doublequoted`).
    let guarded = lemma_guarded_input(lem, macros, predicates, arity1);

    // Proof tail: the prover's result if `--prove` ran, else `by sorry`
    // (the no-prove echo always renders `by sorry`).
    let proof = proved.iter()
        .find(|p| p.name == lem.name)
        .and_then(|p| p.proof_body.as_deref());

    crate::pretty_clean_adapt::lemma_section(
        &lem.name,
        &attrs,
        &lem.trace_quantifier,
        &stmt_formula,
        Some(guarded),
        proof,
    )
}

/// Build the guarded-formula comment body for a lemma (the opaque text the
/// clean crate frames as `/* … */`).  Mirrors the ported `render_guarded_block`
/// content: macro-expand + predicate-expand + arity-1 fold the formula, convert
/// to guarded form, negate for all-traces, and render via
/// `pretty_guarded_doublequoted`; on conversion failure emit the un-indented
/// failure body (the clean crate re-indents it under its own header).
fn lemma_guarded_input(
    lem: &p::Lemma,
    macros: &[p::Macro],
    predicates: &[p::Predicate],
    arity1: &std::collections::HashSet<String>,
) -> crate::pretty_clean_adapt::GuardedInput {
    use crate::pretty_clean_adapt::GuardedInput;
    // HS `parseLemmaWithMacros` applies macros to the lemma formula before the
    // guarded conversion (the guarded block shows the EXPANDED formula).
    let expanded_formula = if macros.is_empty() {
        lem.formula.clone()
    } else {
        crate::macro_expand::apply_macros_formula(macros, &lem.formula)
    };
    let expanded_formula = expand_predicates_for_display(&expanded_formula, predicates);
    let expanded_formula = crate::elaborate::rewrite_arity1_formula(&expanded_formula, arity1);
    let gf = match crate::guarded::formula_to_guarded(&expanded_formula) {
